import{_ as a,o as e,c as o,a2 as r}from"./chunks/framework.B8zgMDLd.js";const p=JSON.parse('{"title":"First Launch","description":"","frontmatter":{},"headers":[],"relativePath":"start/first-launch.md","filePath":"start/first-launch.md"}'),l={name:"start/first-launch.md"};function i(s,t,n,d,c,h){return e(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="first-launch" tabindex="-1">First Launch <a class="header-anchor" href="#first-launch" aria-label="Permalink to &quot;First Launch&quot;">​</a></h1><p>The first launch flow is designed to get you into a real vault quickly without hiding the local-first model.</p><h2 id="what-you-choose" tabindex="-1">What You Choose <a class="header-anchor" href="#what-you-choose" aria-label="Permalink to &quot;What You Choose&quot;">​</a></h2><p>Tolaria asks whether you want to:</p><ul><li>Create or clone the Getting Started vault.</li><li>Open an existing local vault.</li><li>Create a new empty vault.</li></ul><p>The Getting Started vault is cloned locally and then disconnected from its remote. That keeps the sample safe to edit without accidentally pushing tutorial changes.</p><h2 id="what-tolaria-creates" tabindex="-1">What Tolaria Creates <a class="header-anchor" href="#what-tolaria-creates" aria-label="Permalink to &quot;What Tolaria Creates&quot;">​</a></h2><p>Tolaria stores app-level settings on the local machine. Your notes stay in the vault folder you choose.</p><table tabindex="0"><thead><tr><th>Data</th><th>Stored in</th></tr></thead><tbody><tr><td>Notes and attachments</td><td>Your vault folder</td></tr><tr><td>Type definitions and saved views</td><td>Your vault folder</td></tr><tr><td>Window size, zoom, recent vaults</td><td>Local app settings</td></tr><tr><td>Cache data</td><td>Rebuildable local cache</td></tr></tbody></table><h2 id="first-commands-to-try" tabindex="-1">First Commands To Try <a class="header-anchor" href="#first-commands-to-try" aria-label="Permalink to &quot;First Commands To Try&quot;">​</a></h2><ul><li><code>Cmd+K</code> / <code>Ctrl+K</code>: open the command palette.</li><li><code>New Note</code>: create a note in the current vault.</li><li><code>Open Getting Started Vault</code>: clone the public sample vault.</li><li><code>Reload Vault</code>: rescan files after external edits.</li></ul><h2 id="ai-setup-prompt" tabindex="-1">AI Setup Prompt <a class="header-anchor" href="#ai-setup-prompt" aria-label="Permalink to &quot;AI Setup Prompt&quot;">​</a></h2><p>Tolaria can show an optional AI agents prompt after a vault is open. It checks common local install locations for supported coding agents and gives you setup paths, but you can dismiss it and use Tolaria without AI.</p>',13)])])}const m=a(l,[["render",i]]);export{p as __pageData,m as default};
